-- SQL Server: check execution plan and I/O stats
SET STATISTICS IO ON;
SET STATISTICS TIME ON;

-- ❌ Function on indexed column breaks the index
SELECT * FROM Orders WHERE YEAR(OrderDate) = 2024;
-- ✅ Rewrite to use index on OrderDate
SELECT * FROM Orders
WHERE OrderDate >= '2024-01-01' AND OrderDate < '2025-01-01';

-- ❌ N+1 problem — 1 query for orders + 1 per order for customer
SELECT * FROM Orders;  -- returns 1000 orders
-- then for each order: SELECT * FROM Customers WHERE Id = @id  -- 1000 more queries!

-- ✅ Use JOIN instead
SELECT o.Id, o.Amount, c.Name
FROM Orders o
INNER JOIN Customers c ON o.CustomerId = c.Id;

-- ❌ SELECT * loads unnecessary columns (wider rows = more I/O)
SELECT * FROM Users WHERE Id = 42;
-- ✅ Only get what you need
SELECT Id, Name, Email FROM Users WHERE Id = 42;

-- Covering index — includes all columns query needs, avoids table lookup
CREATE INDEX IX_Orders_Cover ON Orders(CustomerId)
INCLUDE (Amount, OrderDate, Status);

-- Basic transaction — bank transfer
BEGIN TRANSACTION;

BEGIN TRY
    -- Debit account A
    UPDATE Accounts
    SET Balance = Balance - 500
    WHERE AccountId = 1 AND Balance >= 500;  -- ensure funds exist

    IF @@ROWCOUNT = 0
        THROW 50001, 'Insufficient funds', 1;

    -- Credit account B
    UPDATE Accounts
    SET Balance = Balance + 500
    WHERE AccountId = 2;

    COMMIT TRANSACTION;
    SELECT 'Transfer successful' AS Result;
END TRY
BEGIN CATCH
    ROLLBACK TRANSACTION;
    SELECT ERROR_MESSAGE() AS ErrorMessage;
END CATCH;

-- Isolation levels (PostgreSQL/SQL Server)
SET TRANSACTION ISOLATION LEVEL READ COMMITTED;  -- default
-- READ UNCOMMITTED: dirty reads allowed (fastest, least safe)
-- REPEATABLE READ: no phantom reads for re-read rows
-- SERIALIZABLE: full isolation (slowest, most safe)

-- VIEW — simplified named query
CREATE VIEW vw_ActiveCustomerOrders AS
SELECT c.Name, c.Email, COUNT(o.Id) AS OrderCount, SUM(o.Amount) AS TotalSpend
FROM Customers c
INNER JOIN Orders o ON c.Id = o.CustomerId
WHERE c.IsActive = 1
GROUP BY c.Id, c.Name, c.Email;

-- Usage: SELECT * FROM vw_ActiveCustomerOrders WHERE TotalSpend > 1000

-- STORED PROCEDURE — parameterized, can do DML
CREATE PROCEDURE usp_ProcessRefund
    @OrderId INT,
    @Reason NVARCHAR(500)
AS BEGIN
    BEGIN TRANSACTION;
    UPDATE Orders SET Status = 'Refunded', UpdatedAt = GETDATE()
    WHERE Id = @OrderId;
    INSERT INTO RefundLog (OrderId, Reason, ProcessedAt)
    VALUES (@OrderId, @Reason, GETDATE());
    COMMIT;
END;
-- EXEC usp_ProcessRefund @OrderId = 42, @Reason = 'Damaged goods';

-- TABLE-VALUED FUNCTION — returns a table, usable in FROM
CREATE FUNCTION fn_GetOrdersByDateRange(@Start DATE, @End DATE)
RETURNS TABLE AS
RETURN SELECT * FROM Orders WHERE OrderDate BETWEEN @Start AND @End;
-- SELECT * FROM fn_GetOrdersByDateRange('2024-01-01','2024-12-31')
